package main

import (
	"fmt"
	"time"
)

type LightDirection string

const (
	NorthSouth LightDirection = "North-South"
	EastWest   LightDirection = "East-West"
)

type LightState string

const (
	Green  LightState = "Green"
	Yellow LightState = "Yellow"
	Red    LightState = "Red"
)

func trafficLight(direction LightDirection, control chan LightDirection, done chan struct{}) {
	currentState := Red
	for {
		select {
		case activeDirection := <-control:
			if activeDirection == direction {
				if currentState != Green {
					currentState = Green
					fmt.Printf("%s light turned %s\n", direction, currentState)
				}
			} else {
				if currentState == Green {
					currentState = Yellow
					fmt.Printf("%s light turned %s\n", direction, currentState)
					time.Sleep(1 * time.Second)
					currentState = Red
					fmt.Printf("%s light turned %s\n", direction, currentState)
				}
			}
		case <-done:
			return
		}
	}
}

func controller(control chan LightDirection, done chan struct{}) {
	directions := []LightDirection{NorthSouth, EastWest}
	index := 0
	for {
		select {
		case <-time.After(5 * time.Second):
			control <- directions[index]
			index = (index + 1) % len(directions)
		case <-done:
			return
		}
	}
}

func main() {
	control := make(chan LightDirection)
	done := make(chan struct{})

	go trafficLight(NorthSouth, control, done)
	go trafficLight(EastWest, control, done)
	go controller(control, done)

	time.Sleep(30 * time.Second)
	close(done)
}
