package main

import (
	"errors"
	"fmt"
	"io/ioutil"
	"net/http"
	"sync"
)

type Result struct {
	Success bool
	Error   error
}

func fetchURL(url string, wg *sync.WaitGroup, ch chan<- Result) {
	defer wg.Done()

	resp, err := http.Get(url)
	if err != nil {
		ch <- Result{Success: false, Error: err}
		return
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		ch <- Result{Success: false, Error: errors.New("non-200 status code")}
		return
	}

	_, err = ioutil.ReadAll(resp.Body)
	if err != nil {
		ch <- Result{Success: false, Error: err}
		return
	}

	ch <- Result{Success: true, Error: nil}
}

func goFunc(urls []string) map[string]int {
	var wg sync.WaitGroup
	ch := make(chan Result, len(urls))

	for _, url := range urls {
		wg.Add(1)
		go fetchURL(url, &wg, ch)
	}

	go func() {
		wg.Wait()
		close(ch)
	}()

	results := make(map[string]int)
	results["success"] = 0
	results["errors"] = 0

	for result := range ch {
		if result.Success {
			results["success"]++
		} else {
			results["errors"]++
		}
	}

	return results
}

func main() {
	urls := []string{"https://example.com", "https://nonexistent.url"}
	results := goFunc(urls)
	fmt.Printf("Success: %d, Errors: %d\n", results["success"], results["errors"])
}
